#nullable enable // autogenerated

using MVZ2Logic.Saves;
using PVZEngine;

namespace MVZ2Logic.Blueprints
{
    public class BlueprintChooseItem
    {
        public NamespaceID id;
        public bool isCommandBlock;
        public bool innate;

        public BlueprintChooseItem(NamespaceID id, bool isCommandBlock = false, bool innate = false)
        {
            this.id = id;
            this.isCommandBlock = isCommandBlock;
            this.innate = innate;
        }
        public BlueprintChooseSaveItem ToSaveItem()
        {
            return new BlueprintChooseSaveItem(id, isCommandBlock);
        }
    }
}
